checkitem.compliant:
( ( COMPONENT = 'ST-PI' and VERSION = '740' and not( (lpad(SP,4,'0')) < '0034' ) )
or ( COMPONENT = 'ST-PI' and VERSION = '758' and not( (lpad(SP,4,'0')) < '0001' ) )
)

checkitem.noncompliant:
( ( COMPONENT = 'ST-PI' and VERSION = '740' and (lpad(SP,4,'0')) < '0034' )
or ( COMPONENT = 'ST-PI' and VERSION = '758' and (lpad(SP,4,'0')) < '0001' )
)

( ( COMPONENT = 'ST-PI' and VERSION = '740' and lpad(SP,4,'0') between '0000' and '0033' )
or ( COMPONENT = 'ST-PI' and VERSION = '758' and lpad(SP,4,'0') = '0000' )
)
